import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

fun fetchExpensesData(timeFrame: String) {
    // Define the date formats for each time frame
    val dateFormat = when (timeFrame) {
        "Weekly" -> SimpleDateFormat("EEEE_dd_MMM_yyyy", Locale.ENGLISH)
        "Monthly" -> SimpleDateFormat("MMM_yyyy", Locale.ENGLISH)
        "Yearly" -> SimpleDateFormat("yyyy", Locale.ENGLISH)
        else -> throw IllegalArgumentException("Unsupported time frame: $timeFrame")
    }

    val query = db.collection("expenses")
        .document("Kantin")
        .collection(timeFrame.toLowerCase())

    query.get().addOnSuccessListener { result ->
        val expenses = mutableListOf<Pair<Float, Date>>()
        for (document in result) {
            val amount = document.getDouble("amount")?.toFloat() ?: 0f
            val date = dateFormat.parse(document.id) ?: Date()
            expenses.add(amount to date)
        }
        // Sort the expenses by date
        expenses.sortBy { it.second }

        // Retain only the amounts for the chart entries
        chartEntries.value = entriesOf(*expenses.map { it.first to 0 }.toTypedArray())
    }
}
```

The code above defines a `SimpleDateFormat` object based on the selected time frame, parses the document name into a `Date` object, collects the expenses as pairs of amounts and dates, sorts the expenses by date, and finally creates the chart entries using only the amounts.

